package com.enterprise.samlsp.security;

import com.enterprise.samlsp.config.SamlSpProperties;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.scheduling.annotation.Scheduled;
import org.springframework.stereotype.Component;

import java.time.Instant;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;

@Component
public class SamlAssertionReplayCache {

    private static final Logger logger = LoggerFactory.getLogger(SamlAssertionReplayCache.class);

    private final ConcurrentHashMap<String, Instant> assertionIdCache = new ConcurrentHashMap<>();
    private final SamlSpProperties properties;

    public SamlAssertionReplayCache(SamlSpProperties properties) {
        this.properties = properties;
    }

    public boolean isReplay(String assertionId) {
        if (assertionId == null || assertionId.isBlank()) {
            logger.warn("Assertion ID is null or blank - treating as replay");
            return true;
        }

        Instant existing = assertionIdCache.putIfAbsent(assertionId, Instant.now());
        if (existing != null) {
            logger.warn("SAML assertion replay detected for assertion ID: {}", assertionId);
            return true;
        }

        logger.debug("Assertion ID {} cached for replay prevention", assertionId);
        return false;
    }

    @Scheduled(fixedDelayString = "${saml.sp.replay-cache-cleanup-interval-ms:60000}")
    public void cleanupExpiredEntries() {
        Instant cutoff = Instant.now().minusSeconds(properties.getReplayCacheExpirationMinutes() * 60L);
        int removedCount = 0;

        for (Map.Entry<String, Instant> entry : assertionIdCache.entrySet()) {
            if (entry.getValue().isBefore(cutoff)) {
                assertionIdCache.remove(entry.getKey());
                removedCount++;
            }
        }

        if (removedCount > 0) {
            logger.debug("Cleaned up {} expired assertion IDs from replay cache", removedCount);
        }
    }

    public int getCacheSize() {
        return assertionIdCache.size();
    }
}

