package com.enterprise.samlsp.security;

import com.enterprise.samlsp.config.SamlSpProperties;
import com.enterprise.samlsp.model.SamlUserAttributes;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.core.io.ResourceLoader;
import org.springframework.stereotype.Component;
import org.w3c.dom.*;
import org.xml.sax.InputSource;

import javax.annotation.PostConstruct;
import javax.xml.XMLConstants;
import javax.xml.crypto.*;
import javax.xml.crypto.dsig.*;
import javax.xml.crypto.dsig.dom.DOMValidateContext;
import javax.xml.crypto.dsig.keyinfo.*;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import java.io.*;
import java.nio.charset.StandardCharsets;
import java.security.Key;
import java.security.PublicKey;
import java.security.cert.CertificateFactory;
import java.security.cert.X509Certificate;
import java.time.Instant;
import java.time.format.DateTimeParseException;
import java.util.Base64;
import java.util.Iterator;
import java.util.zip.Inflater;
import java.util.zip.InflaterInputStream;

@Component
public class SamlResponseParser {

    private static final Logger logger = LoggerFactory.getLogger(SamlResponseParser.class);

    private static final String SAML2_ASSERTION_NS = "urn:oasis:names:tc:SAML:2.0:assertion";
    private static final String SAML2_PROTOCOL_NS = "urn:oasis:names:tc:SAML:2.0:protocol";
    private static final String XMLDSIG_NS = "http://www.w3.org/2000/09/xmldsig#";
    private static final String STATUS_SUCCESS = "urn:oasis:names:tc:SAML:2.0:status:Success";

    private final SamlSpProperties properties;
    private final ResourceLoader resourceLoader;
    private X509Certificate idpCertificate;

    public SamlResponseParser(SamlSpProperties properties, ResourceLoader resourceLoader) {
        this.properties = properties;
        this.resourceLoader = resourceLoader;
    }

    @PostConstruct
    public void init() throws Exception {
        loadIdpCertificate();
    }

    private void loadIdpCertificate() throws Exception {
        try (InputStream is = resourceLoader.getResource(properties.getIdpCertificatePath()).getInputStream()) {
            CertificateFactory cf = CertificateFactory.getInstance("X.509");
            idpCertificate = (X509Certificate) cf.generateCertificate(is);
            logger.info("Loaded IdP certificate: subject={}, expires={}",
                    idpCertificate.getSubjectX500Principal(), idpCertificate.getNotAfter());
        }
    }

    public SamlUserAttributes parseSamlResponse(String samlResponseBase64) throws SamlProcessingException {
        try {
            byte[] decodedBytes = Base64.getDecoder().decode(samlResponseBase64);
            String samlResponseXml = new String(decodedBytes, StandardCharsets.UTF_8);

            Document document = parseXmlSecurely(samlResponseXml);

            validateResponseStatus(document);
            validateSignature(document);

            Element assertion = extractAssertion(document);
            if (assertion == null) {
                throw new SamlProcessingException("No assertion found in SAML response");
            }

            SamlUserAttributes userAttributes = extractUserAttributes(assertion);

            validateAssertion(userAttributes);

            logger.info("Successfully parsed SAML response for user: {}", userAttributes.getNameId());
            return userAttributes;

        } catch (SamlProcessingException e) {
            throw e;
        } catch (Exception e) {
            logger.error("Failed to parse SAML response", e);
            throw new SamlProcessingException("Failed to parse SAML response: " + e.getMessage(), e);
        }
    }

    private Document parseXmlSecurely(String xml) throws Exception {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        factory.setNamespaceAware(true);

        // Prevent XXE attacks
        factory.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
        factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
        factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
        factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
        factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
        factory.setXIncludeAware(false);
        factory.setExpandEntityReferences(false);

        DocumentBuilder builder = factory.newDocumentBuilder();
        InputSource inputSource = new InputSource(new StringReader(xml));
        return builder.parse(inputSource);
    }

    private void validateResponseStatus(Document document) throws SamlProcessingException {
        NodeList statusCodeNodes = document.getElementsByTagNameNS(SAML2_PROTOCOL_NS, "StatusCode");
        if (statusCodeNodes.getLength() == 0) {
            throw new SamlProcessingException("No StatusCode element found in SAML response");
        }

        Element statusCode = (Element) statusCodeNodes.item(0);
        String statusValue = statusCode.getAttribute("Value");

        if (!STATUS_SUCCESS.equals(statusValue)) {
            throw new SamlProcessingException("SAML response status is not Success: " + statusValue);
        }

        logger.debug("SAML response status: Success");
    }

    private void validateSignature(Document document) throws SamlProcessingException {
        try {
            NodeList signatureNodes = document.getElementsByTagNameNS(XMLDSIG_NS, "Signature");
            if (signatureNodes.getLength() == 0) {
                throw new SamlProcessingException("No XML signature found in SAML response");
            }

            Element signatureElement = (Element) signatureNodes.item(0);

            // Determine the parent of the signature to set as the context node
            Node signatureParent = signatureElement.getParentNode();

            DOMValidateContext validateContext = new DOMValidateContext(
                    new X509KeySelector(), signatureElement);

            // Set ID attribute awareness for both Response and Assertion elements
            setIdAttributes(document, validateContext);

            XMLSignatureFactory signatureFactory = XMLSignatureFactory.getInstance("DOM");
            XMLSignature signature = signatureFactory.unmarshalXMLSignature(validateContext);

            boolean isValid = signature.validate(validateContext);

            if (!isValid) {
                // Detailed validation logging
                boolean signatureValueValid = signature.getSignatureValue().validate(validateContext);
                logger.error("Signature value validation: {}", signatureValueValid);

                for (Object ref : signature.getSignedInfo().getReferences()) {
                    Reference reference = (Reference) ref;
                    boolean refValid = reference.validate(validateContext);
                    logger.error("Reference URI={} validation: {}", reference.getURI(), refValid);
                }

                throw new SamlProcessingException("XML signature validation failed");
            }

            logger.debug("XML signature validation successful");

        } catch (SamlProcessingException e) {
            throw e;
        } catch (Exception e) {
            throw new SamlProcessingException("Signature validation error: " + e.getMessage(), e);
        }
    }

    private void setIdAttributes(Document document, DOMValidateContext validateContext) {
        // Set ID attribute for Response element
        NodeList responseNodes = document.getElementsByTagNameNS(SAML2_PROTOCOL_NS, "Response");
        for (int i = 0; i < responseNodes.getLength(); i++) {
            Element element = (Element) responseNodes.item(i);
            if (element.hasAttribute("ID")) {
                validateContext.setIdAttributeNS(element, null, "ID");
            }
        }

        // Set ID attribute for Assertion elements
        NodeList assertionNodes = document.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Assertion");
        for (int i = 0; i < assertionNodes.getLength(); i++) {
            Element element = (Element) assertionNodes.item(i);
            if (element.hasAttribute("ID")) {
                validateContext.setIdAttributeNS(element, null, "ID");
            }
        }
    }

    private Element extractAssertion(Document document) {
        NodeList assertions = document.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Assertion");
        if (assertions.getLength() > 0) {
            return (Element) assertions.item(0);
        }
        return null;
    }

    private SamlUserAttributes extractUserAttributes(Element assertion) throws SamlProcessingException {
        SamlUserAttributes userAttributes = new SamlUserAttributes();

        // Extract Assertion ID
        String assertionId = assertion.getAttribute("ID");
        userAttributes.setAssertionId(assertionId);

        // Extract IssueInstant
        String issueInstantStr = assertion.getAttribute("IssueInstant");
        if (issueInstantStr != null && !issueInstantStr.isEmpty()) {
            try {
                userAttributes.setAssertionIssueInstant(Instant.parse(issueInstantStr));
            } catch (DateTimeParseException e) {
                logger.warn("Could not parse assertion IssueInstant: {}", issueInstantStr);
            }
        }

        // Extract Issuer
        NodeList issuerNodes = assertion.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Issuer");
        if (issuerNodes.getLength() > 0) {
            userAttributes.setIssuer(issuerNodes.item(0).getTextContent().trim());
        }

        // Extract Subject/NameID
        extractSubject(assertion, userAttributes);

        // Extract Conditions (audience restriction)
        extractConditions(assertion, userAttributes);

        // Extract AuthnStatement
        extractAuthnStatement(assertion, userAttributes);

        // Extract AttributeStatement
        extractAttributeStatement(assertion, userAttributes);

        return userAttributes;
    }

    private void extractSubject(Element assertion, SamlUserAttributes userAttributes) throws SamlProcessingException {
        NodeList subjectNodes = assertion.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Subject");
        if (subjectNodes.getLength() == 0) {
            throw new SamlProcessingException("No Subject element found in assertion");
        }

        Element subject = (Element) subjectNodes.item(0);

        // Extract NameID
        NodeList nameIdNodes = subject.getElementsByTagNameNS(SAML2_ASSERTION_NS, "NameID");
        if (nameIdNodes.getLength() > 0) {
            Element nameIdElement = (Element) nameIdNodes.item(0);
            userAttributes.setNameId(nameIdElement.getTextContent().trim());
            String format = nameIdElement.getAttribute("Format");
            if (format != null && !format.isEmpty()) {
                userAttributes.setNameIdFormat(format);
            }
        }

        // Validate SubjectConfirmation
        NodeList confirmationNodes = subject.getElementsByTagNameNS(SAML2_ASSERTION_NS, "SubjectConfirmation");
        if (confirmationNodes.getLength() > 0) {
            Element confirmation = (Element) confirmationNodes.item(0);
            String method = confirmation.getAttribute("Method");
            if (!"urn:oasis:names:tc:SAML:2.0:cm:bearer".equals(method)) {
                logger.warn("Unexpected SubjectConfirmation method: {}", method);
            }

            NodeList confirmationDataNodes = confirmation.getElementsByTagNameNS(SAML2_ASSERTION_NS, "SubjectConfirmationData");
            if (confirmationDataNodes.getLength() > 0) {
                Element confirmationData = (Element) confirmationDataNodes.item(0);

                // Validate Recipient
                String recipient = confirmationData.getAttribute("Recipient");
                if (recipient != null && !recipient.isEmpty() && !recipient.equals(properties.getAcsUrl())) {
                    throw new SamlProcessingException("SubjectConfirmationData Recipient mismatch. Expected: "
                            + properties.getAcsUrl() + ", Got: " + recipient);
                }

                // Validate NotOnOrAfter
                String notOnOrAfterStr = confirmationData.getAttribute("NotOnOrAfter");
                if (notOnOrAfterStr != null && !notOnOrAfterStr.isEmpty()) {
                    try {
                        Instant notOnOrAfter = Instant.parse(notOnOrAfterStr);
                        if (Instant.now().isAfter(notOnOrAfter)) {
                            throw new SamlProcessingException("SubjectConfirmationData has expired. NotOnOrAfter: " + notOnOrAfterStr);
                        }
                    } catch (DateTimeParseException e) {
                        logger.warn("Could not parse NotOnOrAfter: {}", notOnOrAfterStr);
                    }
                }
            }
        }

        if (userAttributes.getNameId() == null || userAttributes.getNameId().isEmpty()) {
            throw new SamlProcessingException("NameID is missing or empty in assertion Subject");
        }
    }

    private void extractConditions(Element assertion, SamlUserAttributes userAttributes) throws SamlProcessingException {
        NodeList conditionsNodes = assertion.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Conditions");
        if (conditionsNodes.getLength() > 0) {
            Element conditions = (Element) conditionsNodes.item(0);

            // Validate NotBefore
            String notBeforeStr = conditions.getAttribute("NotBefore");
            if (notBeforeStr != null && !notBeforeStr.isEmpty()) {
                try {
                    Instant notBefore = Instant.parse(notBeforeStr);
                    // Allow small clock skew (60 seconds)
                    if (Instant.now().plusSeconds(60).isBefore(notBefore)) {
                        throw new SamlProcessingException("Assertion is not yet valid. NotBefore: " + notBeforeStr);
                    }
                } catch (DateTimeParseException e) {
                    logger.warn("Could not parse NotBefore: {}", notBeforeStr);
                }
            }

            // Validate NotOnOrAfter
            String notOnOrAfterStr = conditions.getAttribute("NotOnOrAfter");
            if (notOnOrAfterStr != null && !notOnOrAfterStr.isEmpty()) {
                try {
                    Instant notOnOrAfter = Instant.parse(notOnOrAfterStr);
                    // Allow small clock skew (60 seconds)
                    if (Instant.now().minusSeconds(60).isAfter(notOnOrAfter)) {
                        throw new SamlProcessingException("Assertion has expired. NotOnOrAfter: " + notOnOrAfterStr);
                    }
                } catch (DateTimeParseException e) {
                    logger.warn("Could not parse NotOnOrAfter: {}", notOnOrAfterStr);
                }
            }

            // Extract AudienceRestriction
            NodeList audienceRestrictionNodes = conditions.getElementsByTagNameNS(SAML2_ASSERTION_NS, "AudienceRestriction");
            if (audienceRestrictionNodes.getLength() > 0) {
                Element audienceRestriction = (Element) audienceRestrictionNodes.item(0);
                NodeList audienceNodes = audienceRestriction.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Audience");
                if (audienceNodes.getLength() > 0) {
                    String audience = audienceNodes.item(0).getTextContent().trim();
                    userAttributes.setAudienceRestriction(audience);
                }
            }
        }
    }

    private void extractAuthnStatement(Element assertion, SamlUserAttributes userAttributes) {
        NodeList authnStatementNodes = assertion.getElementsByTagNameNS(SAML2_ASSERTION_NS, "AuthnStatement");
        if (authnStatementNodes.getLength() > 0) {
            Element authnStatement = (Element) authnStatementNodes.item(0);

            String authnInstantStr = authnStatement.getAttribute("AuthnInstant");
            if (authnInstantStr != null && !authnInstantStr.isEmpty()) {
                try {
                    userAttributes.setAuthenticationInstant(Instant.parse(authnInstantStr));
                } catch (DateTimeParseException e) {
                    logger.warn("Could not parse AuthnInstant: {}", authnInstantStr);
                }
            }

            String sessionIndex = authnStatement.getAttribute("SessionIndex");
            if (sessionIndex != null && !sessionIndex.isEmpty()) {
                userAttributes.setSessionIndex(sessionIndex);
            }
        }
    }

    private void extractAttributeStatement(Element assertion, SamlUserAttributes userAttributes) {
        NodeList attrStatementNodes = assertion.getElementsByTagNameNS(SAML2_ASSERTION_NS, "AttributeStatement");
        if (attrStatementNodes.getLength() == 0) {
            logger.debug("No AttributeStatement found in assertion");
            return;
        }

        Element attrStatement = (Element) attrStatementNodes.item(0);
        NodeList attributeNodes = attrStatement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Attribute");

        for (int i = 0; i < attributeNodes.getLength(); i++) {
            Element attribute = (Element) attributeNodes.item(i);
            String attrName = attribute.getAttribute("Name");

            if (attrName == null || attrName.isEmpty()) {
                continue;
            }

            NodeList valueNodes = attribute.getElementsByTagNameNS(SAML2_ASSERTION_NS, "AttributeValue");
            for (int j = 0; j < valueNodes.getLength(); j++) {
                String value = valueNodes.item(j).getTextContent();
                if (value != null) {
                    userAttributes.addAttribute(attrName, value.trim());
                }
            }

            logger.debug("Extracted SAML attribute: {} with {} values", attrName, valueNodes.getLength());
        }
    }

    private void validateAssertion(SamlUserAttributes userAttributes) throws SamlProcessingException {
        // Validate Issuer
        if (userAttributes.getIssuer() == null || !userAttributes.getIssuer().equals(properties.getIdpEntityId())) {
            throw new SamlProcessingException("Assertion Issuer mismatch. Expected: "
                    + properties.getIdpEntityId() + ", Got: " + userAttributes.getIssuer());
        }

        // Validate Audience
        if (userAttributes.getAudienceRestriction() != null
                && !userAttributes.getAudienceRestriction().equals(properties.getEntityId())) {
            throw new SamlProcessingException("Audience restriction mismatch. Expected: "
                    + properties.getEntityId() + ", Got: " + userAttributes.getAudienceRestriction());
        }

        // Validate assertion age
        if (userAttributes.getAssertionIssueInstant() != null) {
            Instant issueInstant = userAttributes.getAssertionIssueInstant();
            Instant maxAge = issueInstant.plusSeconds(properties.getAssertionValiditySeconds());
            if (Instant.now().isAfter(maxAge)) {
                throw new SamlProcessingException("Assertion is too old. IssueInstant: " + issueInstant);
            }
        }

        logger.debug("Assertion validation passed for user: {}", userAttributes.getNameId());
    }

    /**
     * X509 Key Selector that validates against the configured IdP certificate.
     */
    private class X509KeySelector extends KeySelector {
        @Override
        public KeySelectorResult select(KeyInfo keyInfo, Purpose purpose,
                                         AlgorithmMethod method, XMLCryptoContext context) throws KeySelectorException {

            if (keyInfo == null) {
                // Use the configured IdP certificate directly
                return () -> idpCertificate.getPublicKey();
            }

            for (Object keyInfoContent : keyInfo.getContent()) {
                if (keyInfoContent instanceof X509Data) {
                    X509Data x509Data = (X509Data) keyInfoContent;
                    for (Object x509Content : x509Data.getContent()) {
                        if (x509Content instanceof X509Certificate) {
                            X509Certificate cert = (X509Certificate) x509Content;
                            // Verify the certificate in the response matches our configured IdP cert
                            if (cert.equals(idpCertificate)) {
                                final PublicKey publicKey = cert.getPublicKey();
                                return () -> publicKey;
                            } else {
                                logger.warn("Certificate in SAML response does not match configured IdP certificate");
                            }
                        }
                    }
                }
            }

            // Fall back to configured IdP certificate
            return () -> idpCertificate.getPublicKey();
        }
    }
}

