package com.enterprise.samlsp.security;

import com.enterprise.samlsp.model.SamlUserAttributes;
import org.springframework.security.authentication.AbstractAuthenticationToken;
import org.springframework.security.core.GrantedAuthority;
import org.springframework.security.core.authority.SimpleGrantedAuthority;

import java.util.Collection;
import java.util.stream.Collectors;

public class SamlAuthenticationToken extends AbstractAuthenticationToken {

    private final String principal;
    private final SamlUserAttributes userAttributes;

    public SamlAuthenticationToken(SamlUserAttributes userAttributes) {
        super(mapAuthorities(userAttributes));
        this.principal = userAttributes.getNameId();
        this.userAttributes = userAttributes;
        setAuthenticated(true);
    }

    private static Collection<? extends GrantedAuthority> mapAuthorities(SamlUserAttributes userAttributes) {
        return userAttributes.getRoles().stream()
                .map(role -> new SimpleGrantedAuthority("ROLE_" + role.toUpperCase()))
                .collect(Collectors.toList());
    }

    @Override
    public Object getCredentials() {
        return null;
    }

    @Override
    public Object getPrincipal() {
        return principal;
    }

    public SamlUserAttributes getUserAttributes() {
        return userAttributes;
    }
}

// --- SAML Authentication Service ---

package com.enterprise.samlsp.security;

import com.enterprise.samlsp.model.SamlUserAttributes;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Service;

import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpSession;

@Service
public class SamlAuthenticationService {

    private static final Logger logger = LoggerFactory.getLogger(SamlAuthenticationService.class);

    public static final String SESSION_ATTR_SAML_USER = "SAML_USER_ATTRIBUTES";
    public static final String SESSION_ATTR_AUTHENTICATED = "SAML_AUTHENTICATED";

    private final SamlResponseParser samlResponseParser;
    private final SamlAssertionReplayCache replayCache;

    public SamlAuthenticationService(SamlResponseParser samlResponseParser,
                                      SamlAssertionReplayCache replayCache) {
        this.samlResponseParser = samlResponseParser;
        this.replayCache = replayCache;
    }

    public SamlUserAttributes processSamlResponse(String samlResponse, HttpServletRequest request)
            throws SamlProcessingException {

        // Parse and validate the SAML response
        SamlUserAttributes userAttributes = samlResponseParser.parseSamlResponse(samlResponse);

        // Check for assertion replay
        String assertionId = userAttributes.getAssertionId();
        if (replayCache.isReplay(assertionId)) {
            throw new SamlProcessingException("SAML assertion replay detected for ID: " + assertionId);
        }

        // Invalidate any existing session to prevent session fixation
        HttpSession existingSession = request.getSession(false);
        if (existingSession != null) {
            existingSession.invalidate();
        }

        // Create new session
        HttpSession session = request.getSession(true);

        // Store user attributes in session
        session.setAttribute(SESSION_ATTR_SAML_USER, userAttributes);
        session.setAttribute(SESSION_ATTR_AUTHENTICATED, true);

        // Store individual attributes for easy access
        if (userAttributes.getEmail() != null) {
            session.setAttribute("user.email", userAttributes.getEmail());
        }
        if (userAttributes.getDisplayName() != null) {
            session.setAttribute("user.displayName", userAttributes.getDisplayName());
        }
        session.setAttribute("user.nameId", userAttributes.getNameId());
        session.setAttribute("user.roles", userAttributes.getRoles());

        // Set up Spring Security context
        SamlAuthenticationToken authToken = new SamlAuthenticationToken(userAttributes);
        SecurityContextHolder.getContext().setAuthentication(authToken);

        logger.info("SAML authentication successful for user: {} (session: {})",
                userAttributes.getNameId(), session.getId());

        return userAttributes;
    }

    public SamlUserAttributes getAuthenticatedUser(HttpSession session) {
        if (session == null) {
            return null;
        }
        Boolean authenticated = (Boolean) session.getAttribute(SESSION_ATTR_AUTHENTICATED);
        if (Boolean.TRUE.equals(authenticated)) {
            return (SamlUserAttributes) session.getAttribute(SESSION_ATTR_SAML_USER);
        }
        return null;
    }

    public void logout(HttpServletRequest request) {
        HttpSession session = request.getSession(false);
        if (session != null) {
            SamlUserAttributes user = (SamlUserAttributes) session.getAttribute(SESSION_ATTR_SAML_USER);
            if (user != null) {
                logger.info("Logging out SAML user: {}", user.getNameId());
            }
            session.invalidate();
        }
        SecurityContextHolder.clearContext();
    }
}

// --- SAML ACS Controller ---

package com.enterprise.samlsp.controller;

import com.enterprise.samlsp.model.SamlUserAttributes;
import com.enterprise.samlsp.security.SamlAuthenticationService;
import com.enterprise.samlsp.security.SamlProcessingException;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.HttpStatus;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.*;

import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import javax.servlet.http.HttpSession;
import java.io.IOException;

@Controller
public class SamlController {

    private static final Logger logger = LoggerFactory.getLogger(SamlController.class);

    private final SamlAuthenticationService authenticationService;

    public SamlController(SamlAuthenticationService authenticationService) {
        this.authenticationService = authenticationService;
    }

    @PostMapping("/saml/acs")
    public void assertionConsumerService(
            @RequestParam("SAMLResponse") String samlResponse,
            @RequestParam(value = "RelayState", required = false) String relayState,
            HttpServletRequest request,
            HttpServletResponse response) throws IOException {

        try {
            logger.debug("Received SAML response at ACS endpoint");

            SamlUserAttributes userAttributes = authenticationService.processSamlResponse(samlResponse, request);

            // Redirect to the original requested URL or default page
            String redirectUrl = "/dashboard";
            if (relayState != null && !relayState.isEmpty() && isValidRelayState(relayState)) {
                redirectUrl = relayState;
            }

            logger.info("SAML SSO successful for user: {}, redirecting to: {}",
                    userAttributes.getNameId(), redirectUrl);

            response.sendRedirect(redirectUrl);

        } catch (SamlProcessingException e) {
            logger.error("SAML authentication failed: {}", e.getMessage());
            response.sendRedirect("/saml/error?message=" + encodeErrorMessage(e.getMessage()));
        }
    }

    @GetMapping("/saml/login")
    public String initiateLogin(HttpServletRequest request) {
        // In a real implementation, this would redirect to the IdP with an AuthnRequest
        logger.info("SAML login initiated");
        return "redirect:/saml/authn-request";
    }

    @GetMapping("/saml/logout")
    public String logout(HttpServletRequest request) {
        authenticationService.logout(request);
        return "redirect:/";
    }

    @GetMapping("/saml/error")
    @ResponseStatus(HttpStatus.UNAUTHORIZED)
    @ResponseBody
    public String samlError(@RequestParam(value = "message", defaultValue = "Authentication failed") String message) {
        return "SAML Authentication Error: " + sanitize(message);
    }

    @GetMapping("/dashboard")
    @ResponseBody
    public String dashboard(HttpSession session) {
        SamlUserAttributes user = authenticationService.getAuthenticatedUser(session);
        if (user == null) {
            return "Not authenticated. Please <a href='/saml/login'>login</a>.";
        }

        StringBuilder sb = new StringBuilder();
        sb.append("<h1>Welcome, ").append(sanitize(user.getDisplayName() != null ? user.getDisplayName() : user.getNameId())).append("</h1>");
        sb.append("<p>Email: ").append(sanitize(user.getEmail())).append("</p>");
        sb.append("<p>NameID: ").append(sanitize(user.getNameId())).append("</p>");
        sb.append("<p>Roles: ").append(sanitize(user.getRoles().toString())).append("</p>");
        sb.append("<h2>All Attributes:</h2><ul>");
        user.getAttributes().forEach((key, values) -> {
            sb.append("<li><strong>").append(sanitize(key)).append("</strong>: ").append(sanitize(values.toString())).append("</li>");
        });
        sb.append("</ul>");
        sb.append("<p><a href='/saml/logout'>Logout</a></p>");

        return sb.toString();
    }

    @GetMapping("/saml/session-info")
    @ResponseBody
    public String sessionInfo(HttpSession session) {
        SamlUserAttributes user = authenticationService.getAuthenticatedUser(session);
        if (user == null) {
            return "{\"authenticated\": false}";
        }
        return "{\"authenticated\": true, \"nameId\": \"" + sanitize(user.getNameId()) + "\", " +
                "\"assertionId\": \"" + sanitize(user.getAssertionId()) + "\"}";
    }

    private boolean isValidRelayState(String relayState) {
        // Only allow relative URLs to prevent open redirect
        return relayState.startsWith("/") && !relayState.startsWith("//");
    }

    private String encodeErrorMessage(String message) {
        if (message == null) return "unknown_error";
        return message.replaceAll("[^a-zA-Z0-9 _.-]", "").substring(0, Math.min(message.length(), 100));
    }

    private String sanitize(String input) {
        if (input == null) return "N/A";
        return input.replace("&", "&amp;")
                .replace("<", "&lt;")
                .replace(">", "&gt;")
                .replace("\"", "&quot;")
                .replace("'", "&#x27;");
    }
}

// --- Security Configuration ---

package com.enterprise.samlsp.config;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.scheduling.annotation.EnableScheduling;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.web.SecurityFilterChain;

@Configuration
@EnableWebSecurity
@EnableScheduling
public class SecurityConfig {

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
        http
            .csrf(csrf -> csrf
                // Disable CSRF for the SAML ACS endpoint since IdP posts to it
                .ignoringAntMatchers("/saml/acs")
            )
            .authorizeRequests(auth -> auth
                .antMatchers("/saml/acs", "/saml/login", "/saml/error", "/saml/metadata", "/").permitAll()
                .antMatchers("/dashboard", "/saml/session-info").authenticated()
                .anyRequest().authenticated()
            )
            .formLogin().disable()
            .httpBasic().disable()
            .logout(logout -> logout
                .logoutUrl("/saml/logout")
                .logoutSuccessUrl("/")
                .invalidateHttpSession(true)
                .clearAuthentication(true)
            )
            .sessionManagement(session -> session
                .sessionFixation().newSession()
                .maximumSessions(1)
                .expiredUrl("/saml/login")
            )
            .headers(headers -> headers
                .frameOptions().deny()
                .xssProtection().block(true)
                .contentTypeOptions()
            );

        return http.build();
    }
}

// --- Session Configuration ---

package com.enterprise.samlsp.config;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.session.MapSessionRepository;
import org.springframework.session.config.annotation.web.http.EnableSpringHttpSession;
import org.springframework.session.web.http.CookieSerializer;
import org.springframework.session.web.http.DefaultCookieSerializer;

import java.util.concurrent.ConcurrentHashMap;

@Configuration
@EnableSpringHttpSession
public class SessionConfig {

    @Bean
    public MapSessionRepository sessionRepository() {
        MapSessionRepository repository = new MapSessionRepository(new ConcurrentHashMap<>());
        repository.setDefaultMaxInactiveInterval(1800); // 30 minutes
        return repository;
    }

    @Bean
    public CookieSerializer cookieSerializer() {
        DefaultCookieSerializer serializer = new DefaultCookieSerializer();
        serializer.setCookieName("ENTERPRISE_SESSION");
        serializer.setUseHttpOnlyCookie(true);
        serializer.setUseSecureCookie(true);
        serializer.setSameSite("Lax");
        serializer.setCookiePath("/");
        return serializer;
    }
}

// --- Health/Status Endpoint for Replay Cache ---

package com.enterprise.samlsp.controller;

import com.enterprise.samlsp.security.SamlAssertionReplayCache;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RestController;

import java.util.HashMap;
import java.util.Map;

@RestController
public class SamlHealthController {

    private final SamlAssertionReplayCache replayCache;

    public SamlHealthController(SamlAssertionReplayCache replayCache) {
        this.replayCache = replayCache;
    }

    @GetMapping("/saml/health")
    public Map<String, Object> health() {
        Map<String, Object> status = new HashMap<>();
        status.put("status", "UP");
        status.put("replayCacheSize", replayCache.getCacheSize());
        return status;
    }
}